var result;
var objResult = { version: Application.version, build: Application.build, operatingSystem: Application.operatingSystem }
result = JSON.stringify(objResult);

var binArray = [];
if (camera.State != 'Not Connected') 
{
    var numberOfBins = camera.lNumberBins;
    for (i = 0; i < numberOfBins; i++)
    {
        var bin= camera.szBinModeFromIndex(i);
        binArray.push({Key : i, Value: bin})
    }
}

JSON.stringify(binArray);

var filterArray = [];
if (camera.filterWheelIsConnected())
{
    var numberOfFilters = camera.lNumberFilters;
    for (i = 0; i < numberOfFilters; i++)
    {
        var filter = camera.szFilterName(i);
        filterArray.push({Key : i, Value: filter })
    }
}
JSON.stringify(filterArray);

sky6StarChart.DocumentProperty(0);
var lat =sky6StarChart.DocPropOut;

sky6StarChart.DocumentProperty(1);
var lon = sky6StarChart.DocPropOut;

sky6StarChart.DocumentProperty(2);
var tz = sky6StarChart.DocPropOut;

sky6StarChart.DocumentProperty(3);
var ele = sky6StarChart.DocPropOut;

sky6StarChart.DocumentProperty(63);
var locationName = sky6StarChart.DocPropOut;

JSON.stringify({ latitude: lat, longitude: lon, timeZoneOffset: tz, elevation: ele, locationName: locationName });

var result;

var objResult = { 
  primaryCamera: 
  {
    model: SelectedHardware.cameraModel,
    manufacturer: SelectedHardware.cameraManufacturer,
    adaptiveOptics: { model: SelectedHardware.adaptiveOpticsModel, manufacturer: SelectedHardware.adaptiveOpticsManufacturer },
    filterWheel: { model: SelectedHardware.filterWheelModel, manufacturer: SelectedHardware.filterWheelManufacturer },
    focuser: { model: SelectedHardware.focuserModel, manufacturer: SelectedHardware.focuserManufacturer },
    rotator: { model: SelectedHardware.rotatorModel, manufacturer: SelectedHardware.rotatorManufacturer },
    videoDevice: { model: SelectedHardware.videoDeviceModel, manufacturer: SelectedHardware.videoDeviceManufacturer }
  }, 
  autoGuider: 
  {
    model: SelectedHardware.autoguiderCameraModel,
    manufacturer: SelectedHardware.autoguiderCameraManufacturer,
    adaptiveOptics: { model: SelectedHardware.autoguiderAdaptiveOpticsModel, manufacturer: SelectedHardware.autoguiderAdaptiveOpticsManufacturer },
    filterWheel: { model: SelectedHardware.autoguiderFilterWheelModel, manufacturer: SelectedHardware.autoguiderFilterWheelManufacturer },
    focuser: { model: SelectedHardware.autoguiderFocuserModel, manufacturer: SelectedHardware.autoguiderFocuserManufacturer },
    rotator: { model: SelectedHardware.autoguiderRotatorModel, manufacturer: SelectedHardware.autoguiderRotatorManufacturer },
    videoDevice: { model: SelectedHardware.autoguiderVideoDeviceModel, manufacturer: SelectedHardware.autoguiderVideoDeviceManufacturer }
  }, 
  dome: { model: SelectedHardware.domeModel, manufacturer: SelectedHardware.domeManufacturer }, 
  mount: { model: SelectedHardware.mountModel, manufacturer: SelectedHardware.mountManufacturer }, 
  opticalTubeAssembly: { model: SelectedHardware.opticalTubeAssemblyModel, manufacturer: SelectedHardware.opticalTubeAssemblyManufacturer }, 
  weatherStation: { model: SelectedHardware.weatherStationModel, manufacturer: SelectedHardware.weatherStationManufacturer } 
};

result = JSON.stringify(objResult);

sky6StarChart.ClickFind({0}, {1});

var objData = [];

for (var p = 0; p < 189; ++p) {{
  if (p != 11) {{ // We dont want this one 
    sky6ObjectInformation.PropertyApplies(p);
    var isValid = sky6ObjectInformation.ObjInfoPropOut;
    if (isValid != 0) {{
      sky6ObjectInformation.PropertyName(p);
      var name = sky6ObjectInformation.ObjInfoPropOut;

      sky6ObjectInformation.Property(p);
      var value = sky6ObjectInformation.ObjInfoPropOut;

      objData.push({{ id: p, name: name, value: String(value) }});
    }}
  }}
}}

JSON.stringify(objData);

sky6StarChart.Find('{0}');
var objData = [];

for (var p = 0; p < 189; ++p) {{
  if (p != 11) {{ // We dont want this one 
    sky6ObjectInformation.PropertyApplies(p);
    var isValid = sky6ObjectInformation.ObjInfoPropOut;
    if (isValid != 0) {{
      sky6ObjectInformation.PropertyName(p);
      var name = sky6ObjectInformation.ObjInfoPropOut;

      sky6ObjectInformation.Property(p);
      var value = sky6ObjectInformation.ObjInfoPropOut;

      objData.push({{ id: p, name: name, value: String(value) }});
    }}
  }}
}}

JSON.stringify(objData);

if (camera.Status == 'Not Connected') 
{
    JSON.stringify({ exposureComplete: true, exposureSuccess: false }); 
}
else if (camera.IsExposureComplete == 0)
{
    JSON.stringify({ exposureComplete: false, state: camera.State, exposureStatus: camera.ExposureStatus }); 
}
else 
{
    JSON.stringify({ exposureComplete: true, exposureSuccess: true,  state: camera.State, exposureStatus: camera.ExposureStatus, fileName: camera.LastImageFileName }); 
}
